# Seeded classification for common variants from your prevalence lists
seed_classification = {
    # Classic CF-causing
    "F508del": "pathogenic",
    "G542X": "pathogenic",
    "621+1G->T": "pathogenic",
    "N1303K": "pathogenic",
    # Gating / responsive (ivacaftor)
    "G551D": "responsive_ivacaftor",
    "R117H": "responsive_ivacaftor",  # context dependent (poly-T), simplify here
    # Add more as needed...
}

# Collate ETI-responsive and ivacaftor lists from your genotype file if present
eti_list = set()
ivacaftor_list = set()
if genotype and "modulator_eligibility_lists" in genotype["genotypes"]:
    lists = genotype["genotypes"]["modulator_eligibility_lists"]
    for v in lists.get("FDA_ETI_responsive", []):
        eti_list.add(v)
    for v in lists.get("Ivacaftor_responsive", []):
        ivacaftor_list.add(v)

def standardize_variant(v):
    if not v:
        return None
    if legacy_map and v in legacy_map:
        return legacy_map[v]
    return v

def get_pathogenicity(v):
    v = standardize_variant(v)
    if not v:
        return "uncertain"
    # seeded labels
    if v in seed_classification:
        return seed_classification[v]
    # extend by lists
    if v in ivacaftor_list:
        return "responsive_ivacaftor"
    if v in eti_list:
        return "responsive_ETI"
    # default unknown
    return "uncertain"

def pathogenic_count(v1, v2):
    cls = [get_pathogenicity(v1), get_pathogenicity(v2)]
    # Count any category that implies CF-causing biology for risk: treat responsive_* as pathogenic
    def is_path(c):
        return c in ("pathogenic", "responsive_ivacaftor", "responsive_ETI")
    return sum(int(is_path(c)) for c in cls)

def get_modulator_group(v1, v2):
    # Grouping logic per your 1–5 scheme
    v1s, v2s = standardize_variant(v1), standardize_variant(v2)
    vs = {v1s, v2s}
    if "F508del" in vs and len(vs) == 1:
        return 1  # F508del homozygous
    if "F508del" in vs and len(vs) >= 1:
        return 2  # F508del heterozygous
    # if either is ETI responsive
    if (v1s in eti_list) or (v2s in eti_list):
        return 3
    # if ivacaftor/tezacaftor responsive but not ETI
    if (v1s in ivacaftor_list) or (v2s in ivacaftor_list):
        return 4
    return 5

def featurize(v1, v2, age=None, sex=None):
    pc = pathogenic_count(v1, v2)
    grp = get_modulator_group(v1, v2)
    sex_male = 1 if str(sex).upper().startswith('M') else 0
    return {
        "variant1": standardize_variant(v1),
        "variant2": standardize_variant(v2),
        "pathogenic_count": pc,
        "mod_group": grp,
        "age": -1 if age is None else age,
        "sex_male": sex_male
